// Dev/test harness for the two-hop delegation demo.
//
// It provides an in-memory credential "signer" (JWS-shaped, unsigned — the
// payload is what matters here) and an engine oracle for `/evaluate/batch`
// that runs the **real** engine delegation rules (`validateDelegationLink` and
// `verifyAttenuation`). That is the point: the demo and the test prove that a
// widening delegate is rejected by the actual enforcement code, not by a
// hand-rolled stand-in. Real deployments use the signed issuer + the HTTP
// engine; this harness only removes the need to stand those up in-process.

import { buildPortAuthAgentCard } from "portauth-a2a";

import { buildAttenuatedClaims, decodeJwsPayload } from "./intermediate.js";

// The engine's attenuation rules live in the sibling engine package. Imported
// for their pure logic only (no DB is touched by these two functions).
import {
  validateDelegationLink,
  verifyAttenuation,
} from "../../../../portauth-engine/src/services/delegationVerifier.js";

const JWS_HEADER = Buffer.from(JSON.stringify({ alg: "none", typ: "vc+jwt" })).toString("base64url");

/** Encode a claim set as an (unsigned) compact-JWS-shaped token. */
export function encodeClaims(claims) {
  const payload = Buffer.from(JSON.stringify(claims)).toString("base64url");
  return `${JWS_HEADER}.${payload}.unsigned`;
}

/** The root credential the customer presents to the intermediate (hop 1). */
export function customerRootCredential({
  credentialId = "urn:vc:customer-root",
  issuerId = "did:web:customer-issuer",
  // The intermediate is the *subject* of the customer's credential, so the
  // engine's continuity rule (child.issuerId === parent.agentId) lets the
  // intermediate re-issue.
  intermediateId = "agent:bank-intake",
  permissions = ["payments:bill_pay"],
  constraints = [
    { type: "NumericLimitConstraint", field: "core.amount", operator: "lte", value: 2500, currency: "USD" },
    { type: "EnumeratedListConstraint", field: "core.recipient_id", allowed: ["utilities", "telco", "mortgage"] },
    { type: "EnumeratedListConstraint", field: "core.geo_region", allowed: ["US"] },
  ],
} = {}) {
  const claims = { credentialId, issuerId, agentId: intermediateId, permissions, constraints };
  return { claims, token: encodeClaims(claims) };
}

/**
 * An `issueDelegatedCredential` implementation for `createIntermediateAgent`
 * that mints the attenuated child in memory. `narrow(parentClaims)` returns the
 * child's `{ permissions?, constraints? }`; a well-behaved intermediate tightens
 * them, a buggy/hostile one widens them (the test drives both).
 */
export function createInMemoryDelegatedIssuer({ intermediateId = "agent:bank-intake", downstreamSubject = "agent:bank-payments", narrow } = {}) {
  return async ({ inboundVc }) => {
    const parentClaims = decodeJwsPayload(inboundVc);
    const attenuation = typeof narrow === "function" ? narrow(parentClaims) : {};
    const childClaims = buildAttenuatedClaims(parentClaims, {
      issuerId: intermediateId,
      audience: downstreamSubject,
      permissions: attenuation.permissions,
      constraints: attenuation.constraints,
    });
    return { credential: encodeClaims(childClaims) };
  };
}

function engineResponse(bodyObject, status = 200) {
  return {
    ok: status >= 200 && status < 300,
    status,
    json: async () => bodyObject,
    text: async () => JSON.stringify(bodyObject),
  };
}

/**
 * A fetch-compatible engine oracle for the downstream receiver. On
 * `/evaluate/batch` it decodes the chain and runs the engine's real continuity
 * and attenuation checks, returning `delegation_widened` (or
 * `delegation_chain_broken`) exactly as the engine would. On `/evaluate` it
 * allows (single-credential hops are out of scope for this harness).
 */
export function createAttenuationEngineOracle({ auditRecordId = "ar_two_hop" } = {}) {
  return async function evaluate(url, options = {}) {
    const body = options.body ? JSON.parse(options.body) : {};
    if (String(url).endsWith("/evaluate/batch")) {
      const chain = (body.credentials || []).map(decodeJwsPayload);
      for (let i = 1; i < chain.length; i++) {
        const link = validateDelegationLink(chain[i - 1], chain[i]);
        if (!link.valid) {
          return engineResponse({ decision: "deny", error: "delegation_chain_broken", message: link.reason });
        }
        const attenuation = verifyAttenuation(chain[i - 1], chain[i]);
        if (!attenuation.valid) {
          return engineResponse({ decision: "deny", error: "delegation_widened", message: attenuation.reason });
        }
      }
      return engineResponse({ decision: "allow", auditRecordId });
    }
    return engineResponse({ decision: "allow", auditRecordId: `${auditRecordId}-single` });
  };
}

/** Build the downstream payments receiver's Agent Card (advertises the extension). */
export function downstreamAgentCard(url = "http://payments.bank.test") {
  return buildPortAuthAgentCard({
    url,
    governanceManifestUrl: `${url}/.well-known/agent-governance`,
  });
}
